import { useEffect, useRef, useState, useCallback } from "react";
import * as THREE from "three";

// ─── Color palette ────────────────────────────────────────────────────
const C = {
  cyan:  "#29B6D5",
  pink:  "#E8335A",
  gold:  "#FFB800",
  dark:  "#030810",
  darker:"#010508",
};

const cn = (...c) => c.filter(Boolean).join(" ");

// ═══════════════════════════════════════════════════════════════════════
// LOGO — embedded directly as base64 so it always loads, no server needed
// ═══════════════════════════════════════════════════════════════════════
const LOGO_URL = "data:image/png;base64,";

// ═══════════════════════════════════════════════════════════════════════
// ANIMATED BEAST COIN — uses the EXACT uploaded image, 360° CSS spin
// ═══════════════════════════════════════════════════════════════════════
function BeastCoinSVG({ size = 220, glow = true, className = "" }) {
  const wrapRef  = useRef(null);
  const frameRef = useRef(null);
  const stateRef = useRef({ t: 0, angle: 0, dragging: false, lastX: 0, velX: 0 });
  const ringRef1 = useRef(null);
  const ringRef2 = useRef(null);
  const coinRef  = useRef(null);
  const glowRef  = useRef(null);

  useEffect(() => {
    const s = stateRef.current;
    let last = performance.now();
    const tick = (now) => {
      frameRef.current = requestAnimationFrame(tick);
      const dt = Math.min((now - last) / 1000, 0.05);
      last = now;
      s.t += dt;
      if (!s.dragging) { s.velX *= 0.96; s.angle += (0.55 + s.velX) * dt; }
      const floatY = Math.sin(s.t * 0.9) * 8;
      const pulse  = 0.65 + Math.sin(s.t * 2.0) * 0.35;
      if (coinRef.current)
        coinRef.current.style.transform = `translateY(${floatY}px) rotateY(${s.angle * 57.296}deg)`;
      if (ringRef1.current) ringRef1.current.style.transform = `rotate(${s.t * 28}deg)`;
      if (ringRef2.current) ringRef2.current.style.transform = `rotate(${-s.t * 46}deg)`;
      if (glowRef.current) {
        const g = 0.4 + pulse * 0.6;
        glowRef.current.style.boxShadow = [
          `0 0 ${22*g}px ${8*g}px rgba(41,182,213,${0.7*g})`,
          `0 0 ${50*g}px ${18*g}px rgba(41,182,213,${0.28*g})`,
          `0 0 ${28*g}px ${5*g}px rgba(153,69,255,${0.45*g})`,
          `inset 0 0 ${16*g}px rgba(41,182,213,${0.12*g})`,
        ].join(", ");
      }
    };
    frameRef.current = requestAnimationFrame(tick);
    const wrap = wrapRef.current;
    const onDown = (e) => { s.dragging=true; s.lastX=e.clientX??(e.touches?.[0]?.clientX??0); s.velX=0; };
    const onMove = (e) => {
      if (!s.dragging) return;
      const x = e.clientX??(e.touches?.[0]?.clientX??0);
      s.velX = (x-s.lastX)*4; s.angle += (x-s.lastX)*0.012; s.lastX=x;
    };
    const onUp = () => { s.dragging=false; };
    wrap.addEventListener("mousedown",onDown); wrap.addEventListener("mousemove",onMove);
    wrap.addEventListener("mouseup",onUp);     wrap.addEventListener("mouseleave",onUp);
    wrap.addEventListener("touchstart",onDown,{passive:true});
    wrap.addEventListener("touchmove",onMove,{passive:true});
    wrap.addEventListener("touchend",onUp);
    return () => {
      cancelAnimationFrame(frameRef.current);
      wrap.removeEventListener("mousedown",onDown); wrap.removeEventListener("mousemove",onMove);
      wrap.removeEventListener("mouseup",onUp);     wrap.removeEventListener("mouseleave",onUp);
      wrap.removeEventListener("touchstart",onDown); wrap.removeEventListener("touchmove",onMove);
      wrap.removeEventListener("touchend",onUp);
    };
  }, []);

  const pad = size * 0.42;
  return (
    <div ref={wrapRef} className={className} style={{
      width: size+pad*2, height: size+pad*2, position:"relative",
      display:"inline-flex", alignItems:"center", justifyContent:"center",
      cursor:"grab", flexShrink:0,
    }}>
      {/* Outer ambient halo */}
      <div style={{
        position:"absolute", width:size+80, height:size+80, borderRadius:"50%",
        background:"radial-gradient(circle, rgba(41,182,213,0.14) 0%, rgba(153,69,255,0.06) 50%, transparent 70%)",
        pointerEvents:"none",
      }}/>
      {/* Ring 2 — pink+purple dashed, CCW */}
      <div ref={ringRef2} style={{
        position:"absolute", width:size+60, height:size+60, borderRadius:"50%",
        border:"3px solid transparent",
        background:`linear-gradient(#010508,#010508) padding-box,
          conic-gradient(#E8335A 0deg,#E8335A 45deg,transparent 45deg,transparent 90deg,
          #9945FF 90deg,#9945FF 135deg,transparent 135deg,transparent 180deg,
          #E8335A 180deg,#E8335A 225deg,transparent 225deg,transparent 270deg,
          #9945FF 270deg,#9945FF 315deg,transparent 315deg,transparent 360deg) border-box`,
        boxShadow:"0 0 12px 3px rgba(232,51,90,0.55), 0 0 24px 6px rgba(153,69,255,0.25)",
        pointerEvents:"none", willChange:"transform",
      }}/>
      {/* Ring 1 — solid cyan, CW */}
      <div ref={ringRef1} style={{
        position:"absolute", width:size+36, height:size+36, borderRadius:"50%",
        border:"4px solid transparent",
        background:`linear-gradient(#010508,#010508) padding-box,
          conic-gradient(#29B6D5 0deg,#29B6D5 120deg,rgba(41,182,213,0.2) 120deg,
          rgba(41,182,213,0.2) 180deg,#29B6D5 180deg,#29B6D5 300deg,
          rgba(41,182,213,0.2) 300deg,rgba(41,182,213,0.2) 360deg) border-box`,
        boxShadow:"0 0 16px 4px rgba(41,182,213,0.7), 0 0 36px 8px rgba(41,182,213,0.22)",
        pointerEvents:"none", willChange:"transform",
      }}/>
      {/* Thin outer purple */}
      <div style={{
        position:"absolute", width:size+84, height:size+84, borderRadius:"50%",
        border:"1.5px solid rgba(153,69,255,0.3)",
        boxShadow:"0 0 10px 2px rgba(153,69,255,0.18)",
        pointerEvents:"none",
      }}/>
      {/* Coin 3D perspective container */}
      <div style={{perspective:size*3, perspectiveOrigin:"50% 50%", pointerEvents:"none"}}>
        <div ref={coinRef} style={{
          width:size, height:size, borderRadius:"50%",
          transformStyle:"preserve-3d", willChange:"transform", position:"relative",
        }}>
          {/* FRONT FACE */}
          <div style={{
            position:"absolute", inset:0, borderRadius:"50%",
            backfaceVisibility:"hidden", overflow:"hidden",
          }}>
            <img src={LOGO_URL} alt="$BEAST"
              style={{ width:"100%", height:"100%", objectFit:"cover",
                display:"block", pointerEvents:"none", userSelect:"none",
                borderRadius:"50%",
              }} draggable={false}/>
            {/* Sheen */}
            <div style={{
              position:"absolute", inset:0, borderRadius:"50%",
              background:"linear-gradient(135deg, rgba(255,255,255,0.22) 0%, transparent 52%)",
              pointerEvents:"none",
            }}/>
            {/* Inner rim */}
            <div style={{
              position:"absolute", inset:0, borderRadius:"50%",
              boxShadow:"inset 0 0 0 3px rgba(41,182,213,0.35), inset 0 0 20px rgba(41,182,213,0.1)",
              pointerEvents:"none",
            }}/>
          </div>
          {/* BACK FACE */}
          <div style={{
            position:"absolute", inset:0, borderRadius:"50%",
            backfaceVisibility:"hidden", transform:"rotateY(180deg)",
            overflow:"hidden",
          }}>
            <img src={LOGO_URL} alt="$BEAST"
              style={{ width:"100%", height:"100%", objectFit:"cover",
                display:"block", pointerEvents:"none", userSelect:"none",
                borderRadius:"50%", transform:"scaleX(-1)",
              }} draggable={false}/>
            <div style={{
              position:"absolute", inset:0, borderRadius:"50%",
              background:"linear-gradient(225deg, rgba(255,255,255,0.12) 0%, transparent 50%)",
              pointerEvents:"none",
            }}/>
            <div style={{
              position:"absolute", inset:0, borderRadius:"50%",
              boxShadow:"inset 0 0 0 3px rgba(41,182,213,0.2)",
              pointerEvents:"none",
            }}/>
          </div>
        </div>
      </div>
      {/* Pulsing cyan rim glow (JS-controlled) */}
      <div ref={glowRef} style={{
        position:"absolute", width:size+8, height:size+8, borderRadius:"50%",
        border:"4px solid rgba(41,182,213,0.65)", pointerEvents:"none", transition:"box-shadow 0.1s",
      }}/>
      {/* Floor shadow */}
      <div style={{
        position:"absolute", bottom:-(pad*0.25), left:"50%", transform:"translateX(-50%)",
        width:size*0.65, height:16, borderRadius:"50%",
        background:"radial-gradient(ellipse, rgba(41,182,213,0.22) 0%, transparent 70%)",
        filter:"blur(6px)", pointerEvents:"none",
      }}/>
    </div>
  );
}
// ═══════════════════════════════════════════════════════════════════════
// FALLING COINS BACKGROUND (canvas)
// ═══════════════════════════════════════════════════════════════════════
function FallingCoinsBackground() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let W = window.innerWidth, H = window.innerHeight;
    canvas.width = W; canvas.height = H;

    // Offscreen coin renderer
    const makeOffscreenCoin = (size) => {
      const oc = document.createElement("canvas");
      oc.width = size * 2; oc.height = size * 2;
      const octx = oc.getContext("2d");
      const cx = size, cy = size, r = size * 0.9;

      // Coin face gradient
      const faceGrad = octx.createRadialGradient(cx - r*0.3, cy - r*0.3, 0, cx, cy, r);
      faceGrad.addColorStop(0, "#e0f8ff");
      faceGrad.addColorStop(0.3, "#29B6D5");
      faceGrad.addColorStop(0.7, "#0a3d50");
      faceGrad.addColorStop(1, "#010c14");

      // Draw face
      octx.beginPath();
      octx.arc(cx, cy, r, 0, Math.PI * 2);
      octx.fillStyle = faceGrad;
      octx.fill();

      // Rim
      octx.beginPath();
      octx.arc(cx, cy, r, 0, Math.PI * 2);
      octx.strokeStyle = "#29B6D5";
      octx.lineWidth = size * 0.06;
      octx.shadowColor = "#29B6D5";
      octx.shadowBlur = size * 0.3;
      octx.stroke();

      // Inner rim
      octx.shadowBlur = 0;
      octx.beginPath();
      octx.arc(cx, cy, r * 0.85, 0, Math.PI * 2);
      octx.strokeStyle = "rgba(255,255,255,0.15)";
      octx.lineWidth = size * 0.02;
      octx.stroke();

      // Lightning bolt
      const s = size * 0.3;
      octx.save();
      octx.translate(cx + s * 0.15, cy - s * 0.2);
      octx.fillStyle = "#E8335A";
      octx.shadowColor = "#E8335A";
      octx.shadowBlur = size * 0.25;
      octx.beginPath();
      octx.moveTo(s*0.3, -s*0.8);
      octx.lineTo(-s*0.1, s*0.05);
      octx.lineTo(s*0.12, s*0.05);
      octx.lineTo(-s*0.3, s*0.8);
      octx.lineTo(s*0.1, -s*0.0);
      octx.lineTo(-s*0.12, -s*0.0);
      octx.closePath();
      octx.fill();
      octx.restore();

      // Sheen
      const sheenGrad = octx.createRadialGradient(cx - r*0.3, cy - r*0.35, 0, cx, cy, r*0.7);
      sheenGrad.addColorStop(0, "rgba(255,255,255,0.3)");
      sheenGrad.addColorStop(1, "rgba(255,255,255,0)");
      octx.beginPath();
      octx.arc(cx, cy, r, 0, Math.PI * 2);
      octx.fillStyle = sheenGrad;
      octx.fill();

      return oc;
    };

    // Cache coin images at different sizes
    const coinCache = {};
    const getCoin = (size) => {
      const key = Math.round(size);
      if (!coinCache[key]) coinCache[key] = makeOffscreenCoin(size);
      return coinCache[key];
    };

    // Coin particles
    class Coin {
      constructor(randomY = false) {
        this.reset(randomY);
      }
      reset(randomY = false) {
        this.size = Math.random() * 22 + 10;
        this.x = Math.random() * W;
        this.y = randomY ? Math.random() * H : -this.size * 3;
        this.vx = (Math.random() - 0.5) * 0.6;
        this.vy = Math.random() * 1.2 + 0.4;
        this.tilt = Math.random() * Math.PI * 2;
        this.tiltSpeed = (Math.random() - 0.5) * 0.04;
        this.alpha = Math.random() * 0.55 + 0.25;
        this.z = this.size / 32; // depth factor
      }
      update() {
        this.y += this.vy;
        this.x += this.vx;
        this.tilt += this.tiltSpeed;
        if (this.y > H + this.size * 3) this.reset();
        if (this.x < -this.size * 3) this.x = W + this.size;
        if (this.x > W + this.size * 3) this.x = -this.size;
      }
      draw() {
        const scaleX = Math.cos(this.tilt);
        if (Math.abs(scaleX) < 0.05) return;
        const img = getCoin(this.size);
        ctx.save();
        ctx.translate(this.x, this.y);
        ctx.scale(scaleX, 1);
        ctx.globalAlpha = this.alpha * Math.max(0.2, Math.abs(scaleX));
        ctx.drawImage(img, -this.size, -this.size, this.size * 2, this.size * 2);
        ctx.restore();
      }
    }

    const coins = Array.from({ length: 55 }, () => new Coin(true));

    // Floating sparks / network
    const sparks = Array.from({ length: 60 }, () => ({
      x: Math.random() * W, y: Math.random() * H,
      vx: (Math.random() - 0.5) * 0.4,
      vy: (Math.random() - 0.5) * 0.4,
      r: Math.random() * 1.8 + 0.4,
      color: Math.random() > 0.5 ? C.cyan : C.pink,
      alpha: Math.random() * 0.5 + 0.2,
    }));

    let frame;
    const draw = () => {
      frame = requestAnimationFrame(draw);
      ctx.clearRect(0, 0, W, H);

      // Network sparks
      ctx.globalAlpha = 1;
      sparks.forEach(s => {
        s.x += s.vx; s.y += s.vy;
        if (s.x < 0 || s.x > W) s.vx *= -1;
        if (s.y < 0 || s.y > H) s.vy *= -1;
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
        ctx.fillStyle = s.color;
        ctx.globalAlpha = s.alpha;
        ctx.shadowColor = s.color;
        ctx.shadowBlur = 6;
        ctx.fill();
      });

      // Connecting lines between nearby sparks
      ctx.shadowBlur = 0;
      for (let i = 0; i < sparks.length; i++) {
        for (let j = i + 1; j < sparks.length; j++) {
          const dx = sparks[i].x - sparks[j].x;
          const dy = sparks[i].y - sparks[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 110) {
            ctx.beginPath();
            ctx.moveTo(sparks[i].x, sparks[i].y);
            ctx.lineTo(sparks[j].x, sparks[j].y);
            ctx.strokeStyle = C.cyan;
            ctx.globalAlpha = (1 - dist / 110) * 0.07;
            ctx.lineWidth = 0.8;
            ctx.stroke();
          }
        }
      }

      // Draw coins on top
      ctx.globalAlpha = 1;
      coins.forEach(c => { c.update(); c.draw(); });
    };
    draw();

    const onResize = () => {
      W = window.innerWidth; H = window.innerHeight;
      canvas.width = W; canvas.height = H;
    };
    window.addEventListener("resize", onResize);
    return () => { cancelAnimationFrame(frame); window.removeEventListener("resize", onResize); };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{ position: "fixed", inset: 0, zIndex: 0, pointerEvents: "none" }}
    />
  );
}

// ═══════════════════════════════════════════════════════════════════════
// THREE.JS HERO COIN — real image texture, face-on, 360° auto-spin + drag
// ═══════════════════════════════════════════════════════════════════════
function CoinScene() {
  const mountRef = useRef(null);
  useEffect(() => {
    const el = mountRef.current;
    if (!el) return;
    const scene  = new THREE.Scene();
    const w = el.clientWidth, h = el.clientHeight;
    const camera = new THREE.PerspectiveCamera(38, w/h, 0.1, 100);
    camera.position.set(0, 0.3, 6.8);
    const renderer = new THREE.WebGLRenderer({ antialias:true, alpha:true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setClearColor(0x000000, 0);
    el.appendChild(renderer.domElement);

    // Lights — bright to show image clearly
    scene.add(new THREE.AmbientLight(0xffffff, 1.2));
    const key = new THREE.PointLight(0xffffff, 8, 20); key.position.set(5,4,6); scene.add(key);
    const fill = new THREE.PointLight(0x29B6D5, 5, 16); fill.position.set(-5,-2,4); scene.add(fill);
    const rim  = new THREE.PointLight(0xE8335A, 4, 14); rim.position.set(0,5,-3); scene.add(rim);
    const pur  = new THREE.PointLight(0x9945FF, 3, 12); pur.position.set(-3,3,2); scene.add(pur);

    // Load the embedded image as texture
    const loader = new THREE.TextureLoader();
    const frontTex = loader.load(LOGO_URL);
    frontTex.colorSpace = THREE.SRGBColorSpace;

    // Back face — same logo but horizontally mirrored (flipped on X so it reads correctly from behind)
    const backTex = loader.load(LOGO_URL);
    backTex.colorSpace = THREE.SRGBColorSpace;
    // Mirror the UV on the back face by repeating with negative offset
    backTex.repeat.set(-1, 1);
    backTex.offset.set(1, 0);

    // ── Coin: CylinderGeometry, rotation.x=PI/2 faces camera, pivot.rotation.y spins it ──
    // Height 0.85 = thick coin edge like the reference screenshot
    const coinGeo = new THREE.CylinderGeometry(1.65, 1.65, 0.85, 128, 4);

    // Side material — deep purple/indigo gradient with metalness (matches reference exactly)
    const sideCanvas = document.createElement("canvas");
    sideCanvas.width = 512; sideCanvas.height = 64;
    const sc2 = sideCanvas.getContext("2d");
    const sideGrad = sc2.createLinearGradient(0, 0, 512, 0);
    sideGrad.addColorStop(0.00, "#6622cc");
    sideGrad.addColorStop(0.10, "#4411aa");
    sideGrad.addColorStop(0.20, "#8844ee");
    sideGrad.addColorStop(0.35, "#5522bb");
    sideGrad.addColorStop(0.50, "#3a1199");
    sideGrad.addColorStop(0.65, "#7733cc");
    sideGrad.addColorStop(0.80, "#5522bb");
    sideGrad.addColorStop(0.90, "#8840e0");
    sideGrad.addColorStop(1.00, "#6622cc");
    sc2.fillStyle = sideGrad;
    sc2.fillRect(0, 0, 512, 64);
    // Add a subtle cyan highlight line near the top and bottom edges
    const edgeHL = sc2.createLinearGradient(0, 0, 0, 64);
    edgeHL.addColorStop(0,    "rgba(41,182,213,0.6)");
    edgeHL.addColorStop(0.08, "rgba(41,182,213,0.15)");
    edgeHL.addColorStop(0.5,  "rgba(0,0,0,0)");
    edgeHL.addColorStop(0.92, "rgba(41,182,213,0.15)");
    edgeHL.addColorStop(1,    "rgba(41,182,213,0.6)");
    sc2.fillStyle = edgeHL;
    sc2.fillRect(0, 0, 512, 64);
    const sideTex = new THREE.CanvasTexture(sideCanvas);
    sideTex.wrapS = THREE.RepeatWrapping;
    sideTex.repeat.set(4, 1);

    const coin = new THREE.Mesh(coinGeo, [
      // Side — purple metallic texture (matches reference)
      new THREE.MeshStandardMaterial({
        map: sideTex,
        metalness: 0.95, roughness: 0.06,
        emissive: 0x330066, emissiveIntensity: 0.4,
      }),
      // Top = front face (image)
      new THREE.MeshStandardMaterial({ map:frontTex, metalness:0.05, roughness:0.1 }),
      // Bottom = back face
      new THREE.MeshStandardMaterial({ map:backTex,  metalness:0.8, roughness:0.1 }),
    ]);
    coin.rotation.x = Math.PI / 2;

    // Rim toruses — wrap the thicker edge. MUST be in pivot so they spin with coin.
    const mkT = (r, tube, col, emCol, emInt) => new THREE.Mesh(
      new THREE.TorusGeometry(r, tube, 20, 120),
      new THREE.MeshStandardMaterial({ color:col, emissive:emCol, emissiveIntensity:emInt, metalness:0.95, roughness:0.04 })
    );

    // Inner cyan rings — one at each face edge
    const rCyan1 = mkT(1.655, 0.04, 0x29B6D5, 0x29B6D5, 1.4);
    const rCyan2 = mkT(1.655, 0.04, 0x29B6D5, 0x29B6D5, 1.4);
    rCyan1.position.z =  0.425;  // front edge
    rCyan2.position.z = -0.425;  // back edge

    // Mid-edge pink ring
    const rPink = mkT(1.66, 0.03, 0xE8335A, 0xE8335A, 1.4);
    rPink.position.z = 0; // dead centre of the thick edge

    // Outer purple glow ring (equator)
    const rPurple = mkT(1.72, 0.018, 0x9945FF, 0x9945FF, 1.5);
    rPurple.position.z = 0;

    // Extra outer glow rings at top/bottom quarter for depth
    const rPurpleT = mkT(1.68, 0.012, 0xaa55ff, 0xaa55ff, 1.2);
    const rPurpleB = mkT(1.68, 0.012, 0xaa55ff, 0xaa55ff, 1.2);
    rPurpleT.position.z =  0.22;
    rPurpleB.position.z = -0.22;

    // Pivot group — spin this for face-on rotation
    const pivot = new THREE.Group();
    pivot.add(coin, rCyan1, rCyan2, rPink, rPurple, rPurpleT, rPurpleB);
    pivot.rotation.x = 0.22;   // slight downward tilt — shows the thick edge immediately
    scene.add(pivot);

    // Particles
    const N = 200;
    const pp = new Float32Array(N*3), pc = new Float32Array(N*3);
    const pal = [[41,182,213],[232,51,90],[153,69,255],[255,184,0]];
    for (let i=0;i<N;i++) {
      const r2=2.6+Math.random()*3.4, th=Math.random()*Math.PI*2, ph=Math.random()*Math.PI;
      pp[i*3]=r2*Math.sin(ph)*Math.cos(th); pp[i*3+1]=r2*Math.sin(ph)*Math.sin(th); pp[i*3+2]=r2*Math.cos(ph);
      const c=pal[i%4]; pc[i*3]=c[0]/255; pc[i*3+1]=c[1]/255; pc[i*3+2]=c[2]/255;
    }
    const pts = new THREE.Points(
      Object.assign(new THREE.BufferGeometry(), {}) ,
      new THREE.PointsMaterial({ size:0.048, vertexColors:true, transparent:true, opacity:0.8 })
    );
    pts.geometry.setAttribute("position", new THREE.BufferAttribute(pp,3));
    pts.geometry.setAttribute("color",    new THREE.BufferAttribute(pc,3));
    scene.add(pts);

    // Drag spin
    let drag=false, lastX=0, vel=0, t=0;
    const onDown=(e)=>{ drag=true; lastX=e.clientX??(e.touches?.[0]?.clientX??0); vel=0; };
    const onMove=(e)=>{ if(!drag)return; const x=e.clientX??(e.touches?.[0]?.clientX??0); vel=(x-lastX)*0.022; pivot.rotation.y+=(x-lastX)*0.016; lastX=x; };
    const onUp=()=>{ drag=false; };
    el.addEventListener("mousedown",onDown); window.addEventListener("mousemove",onMove); window.addEventListener("mouseup",onUp);
    el.addEventListener("touchstart",onDown,{passive:true}); window.addEventListener("touchmove",(e)=>onMove(e.touches?e:e),{passive:true}); window.addEventListener("touchend",onUp);

    let frame;
    const animate = () => {
      frame = requestAnimationFrame(animate);
      t += 0.013;
      if (!drag) { vel*=0.97; pivot.rotation.y += 0.010 + vel; }
      pivot.position.y = Math.sin(t*0.85)*0.18;
      pivot.rotation.x = 0.22 + Math.sin(t * 0.4) * 0.06; // subtle X bob shows edge
      key.position.x   = Math.sin(t*0.5)*5;
      fill.position.x  = Math.cos(t*0.6)*5;
      rPink.material.emissiveIntensity   = 1.1 + Math.sin(t*2.2)*0.35;
      rPurple.material.emissiveIntensity = 1.1 + Math.sin(t*1.9+1)*0.35;
      rPurpleT.material.emissiveIntensity= 0.9 + Math.sin(t*2.4+0.5)*0.3;
      rPurpleB.material.emissiveIntensity= 0.9 + Math.sin(t*2.4+1.5)*0.3;
      rCyan1.material.emissiveIntensity  = 1.0 + Math.sin(t*2.0+2)*0.25;
      rCyan2.material.emissiveIntensity  = rCyan1.material.emissiveIntensity;
      pts.rotation.y += 0.003;
      renderer.render(scene, camera);
    };
    animate();

    const onResize=()=>{ const nw=el.clientWidth,nh=el.clientHeight; camera.aspect=nw/nh; camera.updateProjectionMatrix(); renderer.setSize(nw,nh); };
    window.addEventListener("resize",onResize);
    return ()=>{ cancelAnimationFrame(frame); el.removeEventListener("mousedown",onDown); window.removeEventListener("mousemove",onMove); window.removeEventListener("mouseup",onUp); window.removeEventListener("resize",onResize); renderer.dispose(); if(el.contains(renderer.domElement))el.removeChild(renderer.domElement); };
  }, []);
  return <div ref={mountRef} style={{ width:"100%", height:"100%", cursor:"grab" }} />;
}
// ═══════════════════════════════════════════════════════════════════════
// HOOKS & UTILS
// ═══════════════════════════════════════════════════════════════════════
function useParallax(factor = 0.3) {
  const [offset, setOffset] = useState(0);
  useEffect(() => {
    const h = () => setOffset(window.scrollY * factor);
    window.addEventListener("scroll", h, { passive: true });
    return () => window.removeEventListener("scroll", h);
  }, [factor]);
  return offset;
}

function Counter({ target, suffix = "", prefix = "" }) {
  const [count, setCount] = useState(0);
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (!e.isIntersecting) return;
      obs.disconnect();
      let start = 0;
      const step = target / 80;
      const timer = setInterval(() => {
        start += step;
        if (start >= target) { setCount(target); clearInterval(timer); }
        else setCount(Math.floor(start));
      }, 18);
    }, { threshold: 0.5 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [target]);
  return <span ref={ref}>{prefix}{count.toLocaleString()}{suffix}</span>;
}

function GlitchText({ children, className = "" }) {
  return <span className={cn("glitch", className)} data-text={children}>{children}</span>;
}

function TiltCard({ children, className = "", style = {} }) {
  const ref = useRef(null);
  const onMove = (e) => {
    const { left, top, width, height } = ref.current.getBoundingClientRect();
    const x = (e.clientX - left) / width  - 0.5;
    const y = (e.clientY - top)  / height - 0.5;
    ref.current.style.transform = `perspective(700px) rotateY(${x*14}deg) rotateX(${-y*14}deg) scale(1.03)`;
  };
  const onLeave = () => { ref.current.style.transform = "perspective(700px) rotateY(0) rotateX(0) scale(1)"; };
  return (
    <div ref={ref} className={cn("tilt-card", className)}
      style={{ transition: "transform 0.15s ease", ...style }}
      onMouseMove={onMove} onMouseLeave={onLeave}>
      {children}
    </div>
  );
}

function Section({ children, className = "", id = "" }) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setVis(true); obs.disconnect(); }
    }, { threshold: 0.08 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <section id={id} ref={ref} className={cn("section-wrapper", vis && "visible", className)}>
      {children}
    </section>
  );
}

