// CSS
// ═══════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════
// CSS — REDESIGN: Dark Luxury × Cyberpunk Editorial
// ═══════════════════════════════════════════════════════════════════════
const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Black+Han+Sans&family=Bebas+Neue&family=Orbitron:wght@400;700;900&family=Space+Mono:wght@400;700&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --cyan:      #29B6D5;
    --pink:      #E8335A;
    --gold:      #FFB800;
    --purple:    #9945FF;
    --dark:      #02060f;
    --darker:    #010408;
    --card-bg:   rgba(8,18,36,0.75);
    --text:      #e8f4fc;
    --muted:     #4a6880;
    --glow-cyan: 0 0 24px #29B6D5, 0 0 70px #29B6D570;
    --glow-pink: 0 0 24px #E8335A, 0 0 70px #E8335A70;
    --glow-gold: 0 0 24px #FFB800, 0 0 60px #FFB80060;
    --font-head: 'Bebas Neue', sans-serif;
    --font-hud:  'Orbitron', monospace;
    --font-body: 'Space Mono', monospace;
    --font-bold: 'Black Han Sans', sans-serif;
    --grid-line: rgba(41,182,213,0.055);
  }

  html { scroll-behavior: smooth; }

  /* ── GLOBAL GRID UNDERLAY ── */
  body {
    background: var(--darker);
    color: var(--text);
    font-family: var(--font-body);
    overflow-x: hidden;
    background-image:
      linear-gradient(var(--grid-line) 1px, transparent 1px),
      linear-gradient(90deg, var(--grid-line) 1px, transparent 1px);
    background-size: 60px 60px;
    background-attachment: fixed;
  }
  /* Vignette over grid */
  body::before {
    content: '';
    position: fixed; inset: 0; z-index: 0; pointer-events: none;
    background: radial-gradient(ellipse 80% 80% at 50% 50%, transparent 40%, var(--darker) 100%);
  }

  ::-webkit-scrollbar { width: 4px; }
  ::-webkit-scrollbar-track { background: var(--darker); }
  ::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, var(--cyan), var(--purple));
    border-radius: 2px;
  }

  /* ── SHIMMER ── */
  .shimmer-text {
    background: linear-gradient(110deg, var(--cyan) 0%, #fff 40%, var(--pink) 70%, var(--cyan) 100%);
    -webkit-background-clip: text; -webkit-text-fill-color: transparent;
    background-size: 250%; animation: shimmer 4s linear infinite;
  }
  @keyframes shimmer { 0%{background-position:200%} 100%{background-position:-200%} }

  /* ── GLITCH ── */
  .glitch { position: relative; color: var(--cyan); }
  .glitch::before, .glitch::after {
    content: attr(data-text); position: absolute; top:0; left:0;
    width:100%; height:100%; background:transparent;
  }
  .glitch::before {
    color: var(--pink); animation: glitch1 3s infinite;
    clip-path: polygon(0 0,100% 0,100% 35%,0 35%); transform: translate(-3px,-2px);
  }
  .glitch::after {
    color: var(--cyan); animation: glitch2 3s infinite;
    clip-path: polygon(0 65%,100% 65%,100% 100%,0 100%); transform: translate(3px,2px);
  }
  @keyframes glitch1 { 0%,100%{transform:translate(-3px,-2px);opacity:0} 10%,20%{opacity:1} 15%{transform:translate(3px,-2px)} }
  @keyframes glitch2 { 0%,100%{transform:translate(3px,2px);opacity:0} 10%,20%{opacity:1} 15%{transform:translate(-3px,2px)} }

  /* ── SCROLL REVEAL ── */
  .section-wrapper {
    opacity:0; transform: translateY(50px) skewY(0.5deg);
    transition: opacity 1s cubic-bezier(0.16,1,0.3,1), transform 1s cubic-bezier(0.16,1,0.3,1);
  }
  .section-wrapper.visible { opacity:1; transform: translateY(0) skewY(0); }

  /* ══════════════════════════════════════════
     NAVBAR
  ══════════════════════════════════════════ */
  .navbar {
    position: fixed; top:0; left:0; right:0; z-index:100;
    display: flex; align-items: center; justify-content: space-between;
    padding: 20px 56px;
    transition: all 0.4s ease;
  }
  .navbar::after {
    content: '';
    position: absolute; bottom:0; left:0; right:0; height:1px;
    background: linear-gradient(90deg, transparent, var(--cyan), var(--pink), transparent);
    opacity: 0; transition: opacity 0.4s;
  }
  .navbar.scrolled {
    background: rgba(1,4,8,0.95);
    backdrop-filter: blur(24px) saturate(180%);
    padding: 14px 56px;
  }
  .navbar.scrolled::after { opacity: 1; }

  .nav-logo { display: flex; align-items: center; gap: 12px; }
  .nav-logo-text { display: flex; flex-direction: column; line-height: 1; }
  .logo-beast {
    font-family: var(--font-bold);
    font-size: 20px; letter-spacing: 4px;
    background: linear-gradient(90deg, var(--cyan), var(--pink));
    -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  }
  .logo-tag {
    font-family: var(--font-hud);
    font-size: 7px; color: var(--gold);
    letter-spacing: 5px; text-transform: uppercase; margin-top: 3px;
  }

  .nav-links { display: flex; gap: 32px; align-items: center; }
  .nav-links a {
    font-family: var(--font-hud); font-size: 9px; font-weight: 700;
    color: rgba(255,255,255,0.5); text-decoration: none;
    letter-spacing: 3px; text-transform: uppercase;
    transition: all 0.25s; position: relative; padding-bottom: 4px;
  }
  .nav-links a::after {
    content: ''; position: absolute; bottom:0; left:0; right:0; height:1px;
    background: linear-gradient(90deg, var(--cyan), var(--pink));
    transform: scaleX(0); transform-origin: left; transition: transform 0.3s;
  }
  .nav-links a:hover { color: var(--cyan); }
  .nav-links a:hover::after { transform: scaleX(1); }
  .nav-yt { color: var(--pink) !important; }
  .nav-cta { display: none; }
  @media(min-width:900px) { .nav-cta { display: block; } }

  /* ══════════════════════════════════════════
     BUTTONS
  ══════════════════════════════════════════ */
  .btn-primary {
    display: inline-flex; align-items: center; gap: 10px;
    background: linear-gradient(135deg, var(--cyan) 0%, #1a78a0 50%, var(--pink) 100%);
    background-size: 200%;
    color: #fff; font-family: var(--font-head); font-size: 20px; letter-spacing: 4px;
    padding: 14px 36px; clip-path: polygon(8px 0%, 100% 0%, calc(100% - 8px) 100%, 0% 100%);
    text-decoration: none; transition: all 0.35s; border: none; cursor: pointer;
    position: relative; overflow: hidden;
    animation: gradShift 4s ease infinite;
  }
  @keyframes gradShift { 0%,100%{background-position:0%} 50%{background-position:100%} }
  .btn-primary::before {
    content: ''; position: absolute; inset: 0;
    background: linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent);
    transform: translateX(-120%); transition: transform 0.5s;
  }
  .btn-primary:hover::before { transform: translateX(120%); }
  .btn-primary:hover { transform: translateY(-3px) scale(1.02); box-shadow: 0 16px 48px rgba(41,182,213,0.4), 0 6px 20px rgba(232,51,90,0.2); }

  .btn-outline {
    display: inline-flex; align-items: center; gap: 10px;
    background: transparent; color: var(--cyan);
    font-family: var(--font-head); font-size: 20px; letter-spacing: 4px;
    padding: 13px 36px;
    clip-path: polygon(8px 0%, 100% 0%, calc(100% - 8px) 100%, 0% 100%);
    border: 1px solid rgba(41,182,213,0.5);
    text-decoration: none; transition: all 0.3s; cursor: pointer;
  }
  .btn-outline:hover {
    background: rgba(41,182,213,0.1); border-color: var(--cyan);
    box-shadow: var(--glow-cyan); transform: translateY(-3px);
  }
  .btn-xl { padding: 18px 48px; font-size: 22px; }
  .btn-glow {
    box-shadow: 0 0 30px rgba(41,182,213,0.5), 0 0 60px rgba(232,51,90,0.2);
    animation: gradShift 4s ease infinite, btnPulse 2.5s ease-in-out infinite;
  }
  @keyframes btnPulse { 0%,100%{box-shadow:0 0 30px rgba(41,182,213,0.5),0 0 60px rgba(232,51,90,0.2)} 50%{box-shadow:0 0 50px rgba(41,182,213,0.8),0 0 100px rgba(232,51,90,0.4)} }

  /* ══════════════════════════════════════════
     HERO
  ══════════════════════════════════════════ */
  .hero {
    position: relative; min-height: 100vh; z-index: 1;
    display: grid; grid-template-columns: 1fr 1fr;
    align-items: center; padding: 120px 56px 80px; gap: 0;
    overflow: hidden;
  }
  /* Diagonal slash divider */
  .hero::after {
    content: '';
    position: absolute; top: -10%; bottom: -10%; left: 50%;
    width: 2px;
    background: linear-gradient(180deg, transparent, var(--cyan), var(--pink), var(--purple), transparent);
    opacity: 0.25; transform: rotate(2deg); pointer-events: none;
  }
  /* Large background lettering */
  .hero::before {
    content: '$BEAST';
    position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%);
    font-family: var(--font-head);
    font-size: clamp(120px, 22vw, 320px);
    color: transparent;
    -webkit-text-stroke: 1px rgba(41,182,213,0.04);
    pointer-events: none; white-space: nowrap; letter-spacing: -10px;
    z-index: 0;
  }

  .hero-text { position: relative; z-index: 1; padding-right: 40px; }

  .hero-badge {
    display: inline-flex; align-items: center; gap: 10px;
    font-family: var(--font-hud); font-size: 9px; font-weight: 700;
    letter-spacing: 4px; text-transform: uppercase; color: var(--cyan);
    background: rgba(41,182,213,0.07);
    border: 1px solid rgba(41,182,213,0.25);
    padding: 9px 20px; margin-bottom: 28px;
    clip-path: polygon(6px 0%, 100% 0%, calc(100% - 6px) 100%, 0% 100%);
    animation: fadeSlideUp 0.8s ease both;
  }
  .badge-dot {
    width: 6px; height: 6px; background: var(--cyan); border-radius: 50%;
    box-shadow: var(--glow-cyan); animation: blink 1.5s infinite;
  }
  @keyframes blink { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:0.2;transform:scale(0.6)} }

  .hero-title {
    font-family: var(--font-head);
    font-size: clamp(80px, 11vw, 150px);
    line-height: 0.85; margin-bottom: 20px;
    animation: fadeSlideUp 0.8s ease 0.1s both;
  }
  .hero-sub {
    display: block;
    font-family: var(--font-hud); font-size: clamp(10px, 1.5vw, 13px);
    color: var(--muted); letter-spacing: 8px; text-transform: uppercase;
    margin-top: 8px; font-weight: 400;
  }
  .hero-desc {
    font-family: var(--font-body); color: var(--muted);
    font-size: 13px; line-height: 2; max-width: 440px;
    margin-bottom: 36px; border-left: 2px solid rgba(41,182,213,0.3);
    padding-left: 20px;
    animation: fadeSlideUp 0.8s ease 0.2s both;
  }
  .hero-buttons { display: flex; gap: 16px; flex-wrap: wrap; margin-bottom: 32px; animation: fadeSlideUp 0.8s ease 0.3s both; }

  /* CA box */
  .ca-box {
    display: flex; align-items: center; gap: 12px; flex-wrap: wrap;
    background: rgba(0,0,0,0.4); border: 1px solid rgba(41,182,213,0.15);
    padding: 12px 20px; margin-bottom: 36px; width: fit-content;
    clip-path: polygon(6px 0%,100% 0%,calc(100% - 6px) 100%,0% 100%);
    animation: fadeSlideUp 0.8s ease 0.4s both;
  }
  .ca-label { font-family: var(--font-hud); font-size: 8px; color: var(--pink); letter-spacing: 4px; text-transform: uppercase; }
  .ca-addr { font-family: var(--font-body); font-size: 11px; color: var(--cyan); letter-spacing: 1px; }
  .ca-copy {
    font-family: var(--font-hud); font-size: 8px; letter-spacing: 3px; text-transform: uppercase;
    background: rgba(41,182,213,0.15); border: 1px solid rgba(41,182,213,0.3);
    color: var(--cyan); padding: 5px 14px; cursor: pointer;
    clip-path: polygon(4px 0%,100% 0%,calc(100% - 4px) 100%,0% 100%);
    transition: all 0.2s;
  }
  .ca-copy:hover { background: rgba(41,182,213,0.3); }

  /* Stats bar */
  .hero-stats {
    display: flex; align-items: stretch; gap: 0;
    border: 1px solid rgba(41,182,213,0.12);
    background: rgba(0,0,0,0.5); width: fit-content;
    animation: fadeSlideUp 0.8s ease 0.5s both;
    overflow: hidden;
    clip-path: polygon(6px 0%,100% 0%,calc(100% - 6px) 100%,0% 100%);
  }
  .stat {
    display: flex; flex-direction: column; align-items: center; justify-content: center;
    padding: 16px 28px; position: relative;
    border-right: 1px solid rgba(41,182,213,0.1);
  }
  .stat:last-child { border-right: none; }
  .stat::before {
    content: ''; position: absolute; top:0; left:0; right:0; height:2px;
    background: linear-gradient(90deg, var(--cyan), var(--pink));
    transform: scaleX(0); transition: transform 0.4s;
  }
  .stat:hover::before { transform: scaleX(1); }
  .stat span:first-child {
    font-family: var(--font-head); font-size: 34px; color: var(--cyan);
    text-shadow: var(--glow-cyan); line-height: 1;
  }
  .stat span:last-child {
    font-family: var(--font-hud); font-size: 7px; color: var(--muted);
    text-transform: uppercase; letter-spacing: 3px; margin-top: 5px;
  }
  .stat-div { display: none; }

  /* Hero coin side */
  .hero-coin-wrap { position: relative; height: 580px; z-index: 1; }
  .hero-coin-3d { width: 100%; height: 100%; }
  .hero-coin-2d { display: none; justify-content: center; align-items: center; height: 100%; }
  .coin-glow {
    position: absolute; bottom: 30px; left: 50%; transform: translateX(-50%);
    width: 400px; height: 60px;
    background: radial-gradient(ellipse, rgba(41,182,213,0.35) 0%, rgba(153,69,255,0.15) 40%, transparent 70%);
    filter: blur(20px); pointer-events: none;
  }

  @keyframes fadeSlideUp { from{opacity:0;transform:translateY(24px)} to{opacity:1;transform:translateY(0)} }

  /* ══════════════════════════════════════════
     TICKER
  ══════════════════════════════════════════ */
  .ticker {
    position: relative; z-index: 1; overflow: hidden; white-space: nowrap;
    padding: 14px 0;
    background: linear-gradient(90deg, var(--dark), rgba(41,182,213,0.08), var(--dark));
    border-top: 1px solid rgba(41,182,213,0.15);
    border-bottom: 1px solid rgba(41,182,213,0.15);
  }
  .ticker::before, .ticker::after {
    content: ''; position: absolute; top:0; bottom:0; width:80px; z-index:2; pointer-events:none;
  }
  .ticker::before { left:0; background: linear-gradient(90deg, var(--dark), transparent); }
  .ticker::after  { right:0; background: linear-gradient(270deg, var(--dark), transparent); }
  .ticker-inner { display: inline-flex; animation: ticker 35s linear infinite; }
  .ticker-item {
    font-family: var(--font-hud); color: var(--muted);
    font-size: 9px; letter-spacing: 4px; text-transform: uppercase;
    padding: 0 48px; display: inline-flex; align-items: center; gap: 12px;
  }
  .ticker-item:nth-child(3n+1) { color: var(--cyan); }
  .ticker-item:nth-child(3n+2) { color: var(--pink); }
  .ticker-item:nth-child(3n+3) { color: var(--gold); }
  @keyframes ticker { 0%{transform:translateX(0)} 100%{transform:translateX(-33.33%)} }

  /* ══════════════════════════════════════════
     SECTION SHARED
  ══════════════════════════════════════════ */
  .section-inner { max-width: 1240px; margin: 0 auto; padding: 0 56px; }
  section { padding: 120px 0; position: relative; z-index: 1; }

  .section-header { text-align: center; margin-bottom: 72px; position: relative; }

  /* Accent rule lines flanking label */
  .section-tag {
    display: inline-flex; align-items: center; gap: 14px;
    font-family: var(--font-hud); font-size: 9px; font-weight: 900;
    letter-spacing: 6px; text-transform: uppercase;
    color: var(--pink); margin-bottom: 20px;
  }
  .section-tag::before, .section-tag::after {
    content: ''; display: inline-block; height: 1px; width: 40px;
    background: linear-gradient(90deg, transparent, var(--pink));
  }
  .section-tag::after { background: linear-gradient(270deg, transparent, var(--pink)); }

  .section-header h2 {
    font-family: var(--font-head);
    font-size: clamp(52px, 8vw, 96px); margin-bottom: 16px; line-height: 1;
    letter-spacing: -1px;
  }
  .section-header p {
    font-family: var(--font-body); color: var(--muted);
    font-size: 12px; line-height: 2; max-width: 480px; margin: 0 auto;
  }

  /* Horizontal scan line separator */
  .section-header::after {
    content: ''; display: block; width: 60px; height: 3px;
    background: linear-gradient(90deg, var(--cyan), var(--pink));
    margin: 20px auto 0;
    clip-path: polygon(4px 0%,100% 0%,calc(100% - 4px) 100%,0% 100%);
  }

  .text-cyan  { color: var(--cyan); }
  .text-pink  { color: var(--pink); }
  .text-gold  { color: var(--gold); }

  /* ══════════════════════════════════════════
     ABOUT / FEATURES
  ══════════════════════════════════════════ */
  .features-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
    gap: 1px;
    background: rgba(41,182,213,0.08);
    border: 1px solid rgba(41,182,213,0.08);
  }
  .feature-card {
    background: var(--card-bg);
    padding: 40px 36px; position: relative; overflow: hidden;
    transition: all 0.4s;
    backdrop-filter: blur(12px);
  }
  /* Diagonal corner accent */
  .feature-card::before {
    content: '';
    position: absolute; top:0; right:0;
    width: 60px; height: 60px;
    background: linear-gradient(225deg, rgba(41,182,213,0.15) 0%, transparent 60%);
    transition: width 0.4s, height 0.4s;
  }
  /* Bottom progress bar on hover */
  .feature-card::after {
    content: '';
    position: absolute; bottom:0; left:0; right:0; height:2px;
    background: linear-gradient(90deg, var(--pink), var(--cyan));
    transform: scaleX(0); transform-origin: left; transition: transform 0.5s;
  }
  .feature-card:hover { background: rgba(12,28,52,0.9); }
  .feature-card:hover::before { width: 100px; height: 100px; }
  .feature-card:hover::after { transform: scaleX(1); }

  .feature-icon {
    width: 54px; height: 54px; margin-bottom: 24px;
    background: rgba(41,182,213,0.07); border: 1px solid rgba(41,182,213,0.2);
    clip-path: polygon(8px 0%,100% 0%,100% calc(100% - 8px),calc(100% - 8px) 100%,0% 100%,0% 8px);
    display: flex; align-items: center; justify-content: center; font-size: 22px;
    transition: all 0.3s;
  }
  .feature-card:hover .feature-icon {
    background: rgba(41,182,213,0.14);
    box-shadow: 0 0 20px rgba(41,182,213,0.2);
  }
  .feature-card h3 {
    font-family: var(--font-bold); font-size: 17px; letter-spacing: 1px;
    margin-bottom: 10px; color: var(--text);
  }
  .feature-card p { font-family: var(--font-body); color: var(--muted); font-size: 11px; line-height: 2; }

  /* ══════════════════════════════════════════
     COIN SHOWCASE
  ══════════════════════════════════════════ */
  .coin-showcase { background: rgba(0,0,0,0.3); overflow: hidden; }
  .coin-showcase section { position: relative; }
  .showcase-grid {
    display: grid; grid-template-columns: 1fr 1fr; gap: 80px;
    align-items: center; max-width: 1000px; margin: 0 auto;
  }
  .showcase-coin-wrap {
    display: flex; justify-content: center; align-items: center;
    position: relative; padding: 50px;
  }
  .showcase-coin-ring1, .showcase-coin-ring2 {
    position: absolute; inset: 0; border-radius: 50%;
    pointer-events: none;
  }
  .showcase-coin-ring1 {
    border: 1px solid rgba(41,182,213,0.18);
    animation: spinRing 12s linear infinite;
    /* Dash simulation */
    background:
      linear-gradient(var(--darker),var(--darker)) padding-box,
      repeating-conic-gradient(rgba(41,182,213,0.4) 0deg 15deg, transparent 15deg 30deg) border-box;
  }
  .showcase-coin-ring2 {
    inset: -20px;
    border: 1px solid rgba(232,51,90,0.12);
    animation: spinRing 18s linear infinite reverse;
    background:
      linear-gradient(var(--darker),var(--darker)) padding-box,
      repeating-conic-gradient(rgba(232,51,90,0.3) 0deg 10deg, transparent 10deg 20deg) border-box;
  }
  @keyframes spinRing { 0%{transform:rotate(0deg)} 100%{transform:rotate(360deg)} }
  .showcase-coin-svg { animation: coinFloat 4.5s ease-in-out infinite; }
  @keyframes coinFloat { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-18px)} }

  .showcase-details { display: flex; flex-direction: column; }
  .showcase-detail-item {
    display: flex; justify-content: space-between; align-items: center;
    padding: 18px 20px;
    border-bottom: 1px solid rgba(255,255,255,0.04);
    position: relative; overflow: hidden;
    transition: all 0.3s;
  }
  .showcase-detail-item::before {
    content: ''; position: absolute; inset:0; left:-100%;
    background: linear-gradient(90deg, transparent, rgba(41,182,213,0.05), transparent);
    transition: left 0.5s;
  }
  .showcase-detail-item:hover::before { left: 100%; }
  .showcase-detail-item:hover { border-bottom-color: rgba(41,182,213,0.15); }
  .showcase-detail-item:last-child { border-bottom: none; }
  .sd-label {
    font-family: var(--font-hud); font-size: 8px;
    color: var(--muted); letter-spacing: 3px; text-transform: uppercase;
  }
  .sd-value {
    font-family: var(--font-body); font-size: 13px; font-weight: 700;
    color: var(--text); letter-spacing: 1px;
  }

  /* ══════════════════════════════════════════
     TOKENOMICS
  ══════════════════════════════════════════ */
  .tokenomics { position: relative; overflow: hidden; }
  /* Large ghost number */
  .tokenomics::before {
    content: '100B';
    position: absolute; top:50%; left:50%; transform:translate(-50%,-50%);
    font-family: var(--font-head); font-size: clamp(160px,25vw,380px);
    color: transparent; -webkit-text-stroke: 1px rgba(41,182,213,0.03);
    pointer-events: none; white-space: nowrap; z-index:0;
  }
  .token-layout {
    display: grid; grid-template-columns: 300px 1fr; gap: 80px;
    align-items: center; margin-bottom: 64px; position: relative; z-index:1;
  }
  .donut-wrap { display: flex; justify-content: center; align-items: center; position: relative; }
  .donut-svg  { width: 300px; height: 300px; filter: drop-shadow(0 0 24px rgba(41,182,213,0.2)); }

  .token-legend { display: flex; flex-direction: column; gap: 12px; }
  .legend-row {
    display: flex; align-items: center; gap: 16px;
    padding: 14px 20px;
    background: var(--card-bg); border: 1px solid rgba(255,255,255,0.04);
    transition: all 0.3s; cursor: default; position: relative; overflow: hidden;
    clip-path: polygon(6px 0%,100% 0%,calc(100% - 6px) 100%,0% 100%);
  }
  .legend-row::before {
    content: ''; position: absolute; left:0; top:0; bottom:0; width:3px;
    background: var(--dot-color, var(--cyan));
  }
  .legend-row:hover { background: rgba(12,28,52,0.9); transform: translateX(4px); }
  .legend-dot {
    width: 10px; height: 10px; border-radius: 50%; flex-shrink: 0;
    box-shadow: 0 0 8px currentColor;
  }
  .legend-label {
    flex:1; font-family: var(--font-hud); font-size: 9px;
    color: var(--text); letter-spacing: 2px; text-transform: uppercase;
  }
  .legend-pct { font-family: var(--font-head); font-size: 28px; }
  .legend-bar-wrap { width: 80px; height: 3px; background: rgba(255,255,255,0.05); }
  .legend-bar { height: 100%; }

  .token-info-grid {
    display: grid; grid-template-columns: repeat(auto-fit, minmax(180px,1fr));
    gap: 1px; background: rgba(41,182,213,0.06); position: relative; z-index:1;
  }
  .token-info-card {
    display: flex; flex-direction: column; gap: 8px;
    background: var(--card-bg); padding: 24px 20px;
    transition: all 0.3s; backdrop-filter: blur(12px);
  }
  .token-info-card:hover { background: rgba(12,28,52,0.9); }
  .ti-label {
    font-family: var(--font-hud); font-size: 8px;
    color: var(--muted); text-transform: uppercase; letter-spacing: 3px;
  }
  .ti-value {
    font-family: var(--font-body); font-size: 15px; font-weight: 700;
    color: var(--cyan); text-shadow: 0 0 10px rgba(41,182,213,0.4);
  }

  /* ══════════════════════════════════════════
     ECOSYSTEM
  ══════════════════════════════════════════ */
  .eco-grid {
    display: grid; grid-template-columns: repeat(auto-fit, minmax(320px,1fr));
    gap: 24px;
  }
  .eco-card {
    background: var(--card-bg); padding: 48px 36px; text-align: center;
    position: relative; overflow: hidden;
    transition: all 0.4s; backdrop-filter: blur(16px);
    clip-path: polygon(0 0, calc(100% - 20px) 0, 100% 20px, 100% 100%, 20px 100%, 0 calc(100% - 20px));
  }
  /* Corner notch glow */
  .eco-card::before {
    content: '';
    position: absolute; top:0; right:0; width:60px; height:60px;
    background: radial-gradient(circle at top right, rgba(255,255,255,0.05), transparent 70%);
    transition: all 0.4s;
  }
  .eco-card::after {
    content: '';
    position: absolute; inset:0;
    background: linear-gradient(135deg, rgba(41,182,213,0.06) 0%, transparent 60%);
    opacity:0; transition: opacity 0.4s;
  }
  .eco-card:hover { transform: translateY(-8px); }
  .eco-card:hover::after { opacity:1; }

  .eco-icon {
    display: inline-flex; align-items: center; justify-content: center;
    width: 80px; height: 80px; font-size: 32px; margin-bottom: 24px;
    clip-path: polygon(12px 0%,100% 0%,100% calc(100% - 12px),calc(100% - 12px) 100%,0% 100%,0% 12px);
    border: 1.5px solid; transition: all 0.3s; position: relative; z-index:1;
  }
  .eco-card h3 {
    font-family: var(--font-head); font-size: 34px; letter-spacing: 2px;
    margin-bottom: 14px; position: relative; z-index:1;
  }
  .eco-card p {
    font-family: var(--font-body); color: var(--muted);
    font-size: 11px; line-height: 2; margin-bottom: 28px; position: relative; z-index:1;
  }
  .eco-btn {
    display: inline-block; padding: 13px 32px;
    font-family: var(--font-head); font-size: 18px; letter-spacing: 3px;
    text-decoration: none; color: #000;
    clip-path: polygon(6px 0%,100% 0%,calc(100% - 6px) 100%,0% 100%);
    transition: all 0.3s; position: relative; z-index:1;
  }
  .eco-btn:hover { opacity: 0.85; transform: translateY(-2px); box-shadow: 0 8px 24px rgba(0,0,0,0.4); }

  /* ══════════════════════════════════════════
     HOW TO BUY
  ══════════════════════════════════════════ */
  .howto { background: rgba(0,0,0,0.25); }
  .steps-grid {
    display: grid; grid-template-columns: repeat(auto-fit, minmax(240px,1fr));
    gap: 1px; background: rgba(41,182,213,0.06);
    margin-bottom: 56px;
  }
  .step-card {
    background: var(--card-bg); padding: 40px 28px; position: relative;
    transition: all 0.3s; backdrop-filter: blur(12px); overflow: hidden;
  }
  /* Large ghost step number */
  .step-num {
    font-family: var(--font-head); font-size: 100px; line-height: 1;
    color: rgba(41,182,213,0.06);
    position: absolute; right: 12px; top: 8px;
    transition: all 0.4s;
  }
  .step-card:hover .step-num { color: rgba(41,182,213,0.12); transform: scale(1.1); }
  .step-card::before {
    content: ''; position: absolute; top:0; left:0; right:0; height:3px;
    background: linear-gradient(90deg, var(--cyan), var(--pink));
    transform: scaleX(0); transform-origin: left; transition: transform 0.4s;
  }
  .step-card:hover { background: rgba(10,22,42,0.95); }
  .step-card:hover::before { transform: scaleX(1); }

  .step-icon { font-size: 36px; margin-bottom: 20px; position: relative; z-index:1; }
  .step-card h3 {
    font-family: var(--font-bold); font-size: 16px; letter-spacing: 1px;
    margin-bottom: 10px; color: var(--cyan); position: relative; z-index:1;
  }
  .step-card p {
    font-family: var(--font-body); color: var(--muted);
    font-size: 11px; line-height: 2; position: relative; z-index:1;
  }
  .step-arrow {
    position: absolute; top:50%; right:-20px; transform:translateY(-50%);
    color: var(--cyan); font-size: 20px; z-index:2; font-weight:bold;
  }
  .buy-ctas { display: flex; justify-content: center; gap: 20px; flex-wrap: wrap; }

  /* ══════════════════════════════════════════
     COMMUNITY
  ══════════════════════════════════════════ */
  .community { text-align: center; padding: 120px 0; }
  .community-inner {
    max-width: 860px; margin: 0 auto; padding: 80px 48px;
    background: var(--card-bg);
    border: 1px solid rgba(41,182,213,0.1);
    position: relative; overflow: hidden;
    clip-path: polygon(0 0,calc(100% - 24px) 0,100% 24px,100% 100%,24px 100%,0 calc(100% - 24px));
    backdrop-filter: blur(20px);
  }
  /* Animated corner accent */
  .community-inner::before {
    content: ''; position: absolute; top:-1px; right:-1px;
    width:100px; height:100px;
    background: linear-gradient(225deg, rgba(41,182,213,0.15), transparent 60%);
    pointer-events: none;
  }
  .community-inner::after {
    content: ''; position: absolute; bottom:-1px; left:-1px;
    width:100px; height:100px;
    background: linear-gradient(45deg, rgba(232,51,90,0.1), transparent 60%);
    pointer-events: none;
  }
  .community-glow {
    position: absolute; top:-80px; left:50%; transform:translateX(-50%);
    width:600px; height:300px;
    background: radial-gradient(ellipse, rgba(41,182,213,0.12) 0%, rgba(153,69,255,0.06) 40%, transparent 70%);
    pointer-events: none;
  }
  .community h2 {
    font-family: var(--font-head);
    font-size: clamp(44px,7vw,88px); margin: 18px 0 20px; line-height:1;
  }
  .community p { font-family: var(--font-body); color: var(--muted); font-size: 12px; line-height:2; margin-bottom: 40px; }
  .social-links { display: flex; justify-content: center; gap: 12px; flex-wrap: wrap; margin-bottom: 44px; }
  .social-btn {
    display: inline-flex; align-items: center; gap: 10px;
    font-family: var(--font-hud); font-size: 9px; letter-spacing: 3px; text-transform: uppercase;
    background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08);
    color: rgba(255,255,255,0.6); padding: 12px 22px;
    clip-path: polygon(6px 0%,100% 0%,calc(100% - 6px) 100%,0% 100%);
    text-decoration: none; transition: all 0.25s;
  }
  .social-btn:hover {
    background: rgba(41,182,213,0.08); border-color: var(--cyan);
    color: var(--cyan); transform: translateY(-2px);
  }

  /* ══════════════════════════════════════════
     FOOTER
  ══════════════════════════════════════════ */
  .footer {
    position: relative; z-index:1;
    padding: 80px 0 44px;
    background: rgba(0,0,0,0.6);
    border-top: 1px solid transparent;
    border-image: linear-gradient(90deg, transparent, var(--cyan), var(--pink), var(--purple), transparent) 1;
  }
  .footer-inner { max-width: 1240px; margin: 0 auto; padding: 0 56px; text-align: center; }
  .footer-logo-wrap {
    display: flex; align-items: center; justify-content: center; gap: 20px; margin-bottom: 24px;
  }
  .footer-logo {
    font-family: var(--font-bold); font-size: 44px; letter-spacing: 8px;
    background: linear-gradient(90deg, var(--cyan), var(--pink), var(--purple));
    -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  }
  .footer-disclaimer {
    font-family: var(--font-body); color: var(--muted);
    font-size: 10px; max-width: 560px; margin: 0 auto 28px; line-height: 2;
  }
  .footer-links { display: flex; justify-content: center; gap: 36px; margin-bottom: 28px; flex-wrap: wrap; }
  .footer-links a {
    font-family: var(--font-hud); color: rgba(255,255,255,0.3);
    text-decoration: none; font-size: 8px; letter-spacing: 4px;
    text-transform: uppercase; transition: color 0.25s; position: relative;
    padding-bottom: 4px;
  }
  .footer-links a::after {
    content: ''; position: absolute; bottom:0; left:0; right:0; height:1px;
    background: var(--cyan); transform:scaleX(0); transform-origin:left; transition:transform 0.3s;
  }
  .footer-links a:hover { color: var(--cyan); }
  .footer-links a:hover::after { transform: scaleX(1); }
  .footer-copy {
    font-family: var(--font-hud); color: rgba(255,255,255,0.12);
    font-size: 8px; letter-spacing: 4px; text-transform: uppercase;
  }

  /* ══════════════════════════════════════════
     RESPONSIVE
  ══════════════════════════════════════════ */
  @media(max-width:900px) {
    .hero { grid-template-columns: 1fr; padding: 110px 24px 60px; gap: 48px; }
    .hero::after { display:none; }
    .hero-coin-3d { display: none; }
    .hero-coin-2d { display: flex; }
    .hero-coin-wrap { height: auto; min-height: 360px; }
    .hero-text { padding-right: 0; }
    .navbar { padding: 16px 24px; }
    .navbar.scrolled { padding: 12px 24px; }
    .nav-links { display: none; }
    .token-layout { grid-template-columns: 1fr; gap: 40px; }
    .showcase-grid { grid-template-columns: 1fr; gap: 40px; }
    .section-inner { padding: 0 24px; }
    .step-arrow { display: none; }
    .legend-bar-wrap { display: none; }
    .legend-row { grid-template-columns: 10px 1fr 36px; }
    .community-inner { padding: 56px 24px; }
    .footer-inner { padding: 0 24px; }
    .btn-xl { padding: 15px 30px; font-size: 18px; }
  }
`;
